// src/types.ts
export interface TodoItem {
  id: number;
  title: string;
  description?: string;
  completed: boolean;
}

// src/api/useApi.ts (Assuming this hook exists as per scaffold)
// For now, I'll assume it works and proceed to App.tsx

// src/App.tsx
import { useState, useEffect } from "react"
import type { TodoItem } from "./types"

// Mock useApi hook for initial build structure (will rely on actual server setup)
const useApi = <T>() => ({ data: [] as T[], loading: false, error: null, create: async () => {}, update: async (id: number, data: Partial<T>) => {}, remove: async (id: number) => {} })

function App() {
  const [todos, setTodos] = useState<TodoItem[]>([])
  const [title, setTitle] = useState("")
  const [description, setDescription] = useState("")

  // Fetch todos on mount
  useEffect(() => {
    const loadTodos = async () => {
      try {
        const response = await fetch("http://localhost:3001/api/items")
        if (!response.ok) throw new Error("Failed to fetch todos")
        const data: TodoItem[] = await response.json()
        setTodos(data)
      } catch (e) {
        console.error("Failed to load todos:", e)
      }
    }
    loadTodos()
  }, [])

  // Add todo
  const addTodo = async () => {
    if (!title.trim()) return
    try {
      const response = await fetch("http://localhost:3001/api/items", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title, description: description }),
      })
      if (!response.ok) throw new Error("Failed to add todo")
      const newItem: TodoItem = await response.json()
      setTodos(prev => [...prev, newItem])
    } catch (e) {
      alert("Could not add todo: " + e?.message || "Unknown error")
    } finally {
      setTitle("")
      setDescription("")
    }
  }

  // Toggle completion status
  const toggleTodo = async (id: number) => {
    try {
      await fetch(`http://localhost:3001/api/items/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ completed: !prevTodo?.completed }),
      })
      setTodos(prev => prev.map(todo => 
        todo.id === id ? {...todo, completed: !todo.completed} : todo
      ))
    } catch (e) {
      alert("Failed to toggle todo: " + e?.message || "Unknown error")
    }
  }

  // Delete todo
  const deleteTodo = async (id: number) => {
    if (!window.confirm("Are you sure you want to delete this item?")) return
    try {
      await fetch(`http://localhost:3001/api/items/${id}`, {
        method: "DELETE",
      })
       setTodos(prev => prev.filter(todo => todo.id !== id))
    } catch (e) {
      alert("Failed to delete todo: " + e?.message || "Unknown error")
    }
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white shadow py-8 px-4 sm:px-6 lg:px-8">
        <div className="max-w-3xl mx-auto flex items-center justify-between">
          <h1 className="text-3xl font-bold text-gray-900">To Do List</h1>
          <button 
            onClick={loadTodos} 
            disabled={loading}
            className={`px-4 py-2 rounded-lg transition duration-150 ${loading ? 'bg-gray-200 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-md hover:shadow-lg'}`}
          >
            {loading ? "Loading..." : "Refresh"}
          </button>
        </div>
      </header>

      <main className="max-w-3xl mx-auto p-4 sm:p-6 lg:p-8">
        {/* Add Todo Form */}
        <div className="bg-white p-6 rounded-xl shadow-lg mb-8 border border-gray-100">
          <h2 className="text-2xl font-semibold text-gray-900 mb-4">Add New Item</h2>
          <form onSubmit={addTodo} className="flex flex-col gap-3">
            <div className="flex items-center gap-3">
              <input 
                type="checkbox" 
                checked={!title.trim()} 
                onChange={(e) => setTitle(e.target.checked ? "" : "Please enter a title")}/>
              <label htmlFor="title" className="text-sm font-medium text-gray-600">Title</label>
            </div>
            <input 
              id="title" 
              type="text" 
              required 
              value={title} 
              onChange={(e) => setTitle(e.target.value)} 
              placeholder="Enter a title..." 
              className="w-full p-3 border border-gray-200 rounded-lg focus:ring-indigo-500 focus:border-indigo-500 outline-none transition duration-150" 
              placeholder="" 
              autoFocus={false} 
            />
            <textarea 
              id="description" 
              rows={4} 
              value={description} 
              onChange={(e) => setDescription(e.target.value)} 
              placeholder="Optional description..." 
              className="w-full p-3 border border-gray-200 rounded-lg focus:ring-indigo-500 focus:border-indigo-500 outline-none transition duration-150 resize-y" 
              placeholder="" 
              required={false} 
            />
            <button 
              type="submit" 
              disabled={!title.trim()} 
              className={`w-full py-3 px-6 rounded-xl text-lg font-medium transition duration-200 ${(!title.trim()) ? 'bg-gray-200 cursor-not-allowed text-gray-500' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-xl hover:shadow-2xl ring-4 ring-indigo-100 active:scale-[0.98]'}`}
            >
              {title.trim() ? "Add Task" : "Please enter a title"}
            </button>
          </form>
        </div>

        {/* Todo List */}
        <div className="space-y-4">
          {todos.length === 0 ? (
            <div className="text-center py-12 bg-white rounded-xl shadow-inner border border-gray-100">
              <p className="text-gray-500 text-lg mb-2">You don't have any tasks!</p>
              <p className="text-gray-400 text-sm">Start by adding one above.</p>
            </div>
          ) : (
            <ul className="space-y-3">
              {todos.map(todo => (
                <li key={todo.id} className={`flex items-center justify-between p-4 rounded-xl transition duration-200 ${todo.completed ? 'bg-green-50 border-l-4 border-green-500' : 'bg-white hover:shadow-lg'} ${todo.completed ? 'opacity-70 line-through text-gray-400' : ''}`}>
                  <input 
                    type="checkbox" 
                    checked={todo.completed} 
                    onChange={() => toggleTodo(todo.id)} 
                  />
                  <div className="flex flex-col gap-1 flex-grow mr-4">
                    <p className={`text-lg ${todo.completed ? 'text-gray-500' : 'text-gray-900'} font-medium`}>{todo.title}</p>
                      <p className={`text-sm ${todo.description ? 'text-gray-600' : 'hidden'}`}>${todo.description}</p>
                    {!todo.description && todo.id !== 1 && <span className="text-xs text-indigo-500 font-normal">No description provided</span>}
                  </div>
                  <div className="flex items-center gap-3">
                    <button 
                      onClick={() => deleteTodo(todo.id)} 
                      className="p-2 rounded-full transition duration-150 bg-red-50 hover:bg-red-100 text-red-600 hover:text-red-700 disabled:opacity-50"
                      disabled={!todo.title}
                    >
                      &times;
                    </button>
                  </div>
                </li>
              ))}
            </ul>
          )}
        </div>
      </main>
    </div>
  )
}

export default App
